import React, { useEffect, useState } from 'react';
import Section1 from '../pages/PageActi/Section1';

export default function Activitie() {
  const [isMount, setIsMount] = useState(false);

  useEffect(() => {
    if (!isMount) {
      window.scrollTo(0, 0);
      setIsMount(true);
    }
  }, [isMount]);

  return (
    <>
      <Section1 />
    </>
  );
}