import React, { useState, useEffect } from 'react';
import './CardTV.css';
import './CardOnClick.css';
const docs = require('../../../api/docs.json');

const Card = ({ name, role, nameImg, ct }) => {
    const imgSrc = require(`../../../assets/img/avt/${nameImg}`);
    const [isModalOpen, setIsModalOpen] = useState(true);
    const showCard = () => {
        setIsModalOpen(true);
        var modal = document.querySelector('.md-modal');
        var overlay = document.querySelector('.md-overlay');
        if (modal !== null && overlay !== null) {
            modal.classList.add('md-show');
            overlay.classList.add('md-show');
        }
    }
    const hideCard = () => {
        setIsModalOpen(false);
        var modal = document.querySelector('.md-modal');
        var overlay = document.querySelector('.md-overlay');
        if (modal !== null && overlay !== null) {
            modal.classList.remove('md-show');
            overlay.classList.remove('md-show');
        }
    }
    useEffect(() => {
        const handleEscKeydown = (event) => {
            if (event.key === 'Escape' && isModalOpen) {
                hideCard();
            }
        };

        document.addEventListener('keydown', handleEscKeydown);
        return () => {
            document.removeEventListener('keydown', handleEscKeydown);
        };
    }, [isModalOpen]);
    return (
        <>
            <div className="card-tv col-lg-3 col-4">
                <div className="card-tv-abs w-100" onClick={showCard}>
                    <img id="img" src={imgSrc} alt="" />
                    <h5>{name}</h5>
                    <div className="content">
                        {role.map((item, index) => (
                            <h6 key={index} > {item.tt}</h6>
                        ))}
                    </div>
                </div>
            </div>
            {isModalOpen && (
                <>
                    <div className='md-modal md-effect-1 ${}'>
                        <div className="md-content text-center p-3">
                            <img id="img" src={imgSrc} alt="" className='w-25 rounded-circle' />
                            <h4>{name}</h4>
                            {role.map((item, index) => (
                                <h5 key={index} > {item.tt}</h5>
                            ))}
                            {ct.map((item, index) => (
                                <p key={index} > {item.tt}</p>
                            ))}
                            <button className="md-close btn btn-primary" onClick={hideCard}>Đóng</button>
                        </div>
                    </div>
                    <div className="md-overlay" onClick={hideCard}></div>
                </>
            )}
        </>
    );
}

const CardTV = ({ TheHe }) => {
    return (
        <div className="row d-flex justify-content-evenly">
            {docs['menber'][TheHe].map((item, index) => (
                <Card key={index} name={item.name} role={item.role} nameImg={item.nameImg} ct={item.ct} />
            ))}
        </div>
    );
};

export default CardTV;