import React, { useState } from 'react'
import QA from '../components/UI/Q&A/QA'
import Section1 from '../pages/PageTTV/Section1'
import FormTTV from '../components/UI/Form/FormTTV'
export default function About() {
  const [ShowForm, SetShowForm] = useState(true);
  const toggleForm = () => {
    SetShowForm(!ShowForm);
  };
  return (
    <>
      <Section1 />
      <div className='my-3'></div>
      {ShowForm && <FormTTV />}
      <QA />
    </>
  )
}
