import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import { Outlet } from 'react-router-dom';
import Header from './components/Header'
import Footer from './components/Footer';
const Load = () => {
  const rootLoad = document.querySelector(".root_load");
  window.addEventListener("load", () => {
    rootLoad.classList.add("active");
  });
}

export default function App() {
  const [GoToTop, SetShowGoToTop] = useState(false);
  const handleGoToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };
  useEffect(() => {
    AOS.init();
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
    const handleScroll = () => {
      SetShowGoToTop(window.scrollY);
    }
    window.addEventListener('scroll', handleScroll);
    return () => {
      window.removeEventListener('scroll', handleScroll);
    }
  }, []);
  // useEffect(() => {
  //   document.addEventListener('keydown', (event) => {
  //     if ((event.key === 'F12' || event.which === 123) || (event.ctrlKey && event.shiftKey && event.key.toLowerCase() === 'i')) {
  //       window.location.href = '/404';
  //     }
  //   });
  // }, [])
  Load();
  return (
    <>
      <Header />
      <Outlet />
      <Footer />
      {GoToTop && (
        <button
          className='GoToTop '
          title='Back to top'
          onClick={handleGoToTop}
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="30" height="30" fill="currentColor" className="bi bi-chevron-up" viewBox="0 0 16 16">
            <path fillRule="evenodd" d="M7.646 4.646a.5.5 0 0 1 .708 0l6 6a.5.5 0 0 1-.708.708L8 5.707l-5.646 5.647a.5.5 0 0 1-.708-.708z" />
          </svg>
        </button>
      )}
    </>
  );
}

