import React from 'react'
import { Form, Button, Row, Col, Container } from 'react-bootstrap'
import { Radio, FormControl, FormControlLabel, FormLabel, RadioGroup } from '@mui/material'

export default function FormTTV() {
  return (
    <>

      <Container>
        <h2>Form tuyển thành viên</h2>
        <Form >
          <Row>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <Form.Label>Họ và tên:</Form.Label>
                <Form.Control name='q' type="text" placeholder="Nhập tên..." />
                <Form.Text className="text-muted">
                  Vui lòng điền đầy đủ và họ và tên của bạn.
                </Form.Text>
              </Form.Group>
            </Col>
            <Col xs={12} lg={3}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <Form.Label>Thông tin khoá của bạn:</Form.Label>
                <Form.Control type="text" placeholder="Nhập lớp..." />
                <Form.Text className="text-muted">
                  Vd: K47B Kỹ Thuật Phần Mền
                </Form.Text>
              </Form.Group>
            </Col>
            <Col xs={12} lg={3}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <FormControl>
                  <Form.Label id="demo-row-radio-buttons-group-label" >Giới tính:</Form.Label>
                  <RadioGroup
                    row
                    aria-labelledby="demo-row-radio-buttons-group-label"
                    name="row-radio-buttons-group"
                  >
                    <FormControlLabel value="female" control={<Radio />} label="Nam" />
                    <FormControlLabel value="male" control={<Radio />} label="Nữ" />
                    <FormControlLabel value="other" control={<Radio />} label="Khác" />
                  </RadioGroup>
                </FormControl>
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicPassword">
                <Form.Label>Email:</Form.Label>
                <Form.Control type="email" placeholder="Email..." />
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicPassword">
                <Form.Label>SDT liên lạc:</Form.Label>
                <Form.Control type="text" placeholder="SDT..." />
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <Form.Label>Nhập điểm hệ 10 môn Nhập môn lập trình:</Form.Label>
                <Form.Control type="number" placeholder="Nhập điểm Nhập môn lập trình..." />
                <Form.Text className="text-muted">
                  Nếu bạn thuộc K46 và chưa có điểm thì vui lòng để trống.
                </Form.Text>
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <Form.Label>Nhập điểm hệ 10 môn Kĩ thuật lập trình</Form.Label>
                <Form.Control type="number" placeholder="Nhập điểm Kĩ thuật lập trình..." />
                <Form.Text className="text-muted">
                  Nếu bạn thuộc K46 và chưa có điểm thì vui lòng để trống.
                </Form.Text>
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicPassword">
                <Form.Label>Điểm mạnh:</Form.Label>
                <Form.Control as="textarea" aria-label="With textarea" placeholder="Nhập điểm mạnh..." />
              </Form.Group>
            </Col>
            <Col xs={12} lg={6}>
              <Form.Group className="mb-3" controlId="formBasicPassword">
                <Form.Label>Điểm yếu:</Form.Label>
                <Form.Control as="textarea" aria-label="With textarea" placeholder="Nhập điểm yếu..." />
              </Form.Group>
            </Col>
            <Col xs={12}>
              <Form.Group className="mb-3" controlId="formBasicEmail">
                <Form.Label>Bạn mong muốn điều gì khi vào clb hỗ trợ lập trình</Form.Label>
                <Form.Control as="textarea" aria-label="With textarea" placeholder="Nhập mong muốn của bạn đối với clb..." />
              </Form.Group>
            </Col>
            <Col xs={12}>
              <Button className='w-100' variant="primary" type="submit">
                Hoàn thành
              </Button>
            </Col>
          </Row>
        </Form>
      </Container>
    </>
  )
}

