import React from 'react'
import { Carousel, Container } from 'react-bootstrap'


export default function Section1() {
    return (
        <>


            <Container className='position-relative' fluid style={{ padding: 0, overflow: 'visible' }}>
                <Carousel className='IntroSlide' indicators={false} style={{
                    marginTop: -70,
                    zIndex: 0
                }}>
                    <Carousel.Item>
                        <img alt='none' className='w-100' style={{ filter: 'brightness(0.85) contrast(1)' }} src={require('../../assets/img/banner.png')} />
                    </Carousel.Item>
                    <Carousel.Item>
                        <img alt='none' className='w-100' src={require('../../assets/img/banner2.png')} />
                    </Carousel.Item>
                </Carousel>
            </Container>
        </>
    )
}
