import React from 'react'
import { Link } from 'react-router-dom'
import { Container, Col, Row, Carousel } from 'react-bootstrap'
const docs = require('../../api/docs.json');

export default function Section1() {
    return (
        <Container fluid className=' position-relative homecl'>
            <Container className='gioithieu' style={{ paddingBottom: 80 }}>
                <div className="ovl1"></div>
                <div className="ovl2"></div>
                <div className="ovl3"></div>
                <div className="ovl"></div>
                <Row className=' d-flex flex-column  flex-lg-row align-items-lg-center'>
                    <Col data-aos="zoom-in-up" data-aos-duration="1000">
                        <Row className='text-center'>
                            <Col xs={12} className='hh h3 texth1 hmtop'>Giới thiệu</Col>
                            <Col xs={12} className='h2 hh gradient-text'>CLB Hỗ Trợ Lập Trình SPIT</Col>
                        </Row>
                        <Row className='mt mt-ht'>
                            <p><strong>CLB Hỗ trợ Lập trình</strong> {docs.GTSPIT} </p>
                            <p className='mt-1 text-spit' style={{ fontSize: 28 }}><strong>Slogan</strong> Lập trình khó có
                                <span className='gradient-text' style={{ fontWeight: 'bold' }}> SPIT </span> lo</p>
                        </Row>
                        <Row className='mt-2  mx-auto my-4'>
                            <Col className='d-flex justify-content-evenly  '>
                                <Link to='/ttv' className='btn-xt'>Tham gia ngay</Link>
                                <Link to='/intro' className='btn-xt  btn-xt-ct'>Xem thêm</Link>
                            </Col>
                        </Row>
                    </Col>
                    <Col className='position-relative' data-aos="zoom-in-up" data-aos-duration="1000" data-aos-delay="100">
                        <Carousel className='w-100' fade controls={true} indicators={false}
                        // style={{ border: '5px solid black' }}
                        >
                            <Carousel.Item interval={5000}>
                                <img src={require('../../assets/img/banner.png')} alt='img clb spit' className=' w-100'></img>
                            </Carousel.Item>
                            <Carousel.Item interval={3000}>
                                <img src={require('../../assets/img/banner2.png')} alt='img clb spit' className=' w-100'></img>
                            </Carousel.Item>
                        </Carousel>
                    </Col>
                </Row>
            </Container>
        </Container>
    )
}
