import React, { useState, useEffect } from 'react';
import './count.css';

const Counter = ({ target, name, plus, time }) => {
    const [count, setCount] = useState(0);
    useEffect(() => {
        const interval = setInterval(() => {
            setCount((prvC) => {
                if (prvC >= target) {
                    clearInterval(interval);
                    return target;
                }
                return prvC + 1;
            });
        }, time);

        return () => clearInterval(interval);
    }, [target, time]);
    return (
        <div className='col-12 col-sm-6 col-md-4 col-lg-3 text-main'>
            <span className="text counter">{count}</span>
            <span className="text">{plus}</span>
            <div className='text-cmt'>{name}</div>
        </div>
    );
};
export default function Count() {
    const counters = ([
        { id: 1, target: 30, name: 'Số thành viên', plus: '', time: 100 },
        { id: 2, target: 30, name: 'Buổi Tranning', plus: '+', time: 100 },
        { id: 3, target: 500, name: 'Số lượt tham gia training', plus: '+', time: 5 },
        { id: 4, target: 80, name: 'Buổi seminar', plus: '', time: 40 },
        { id: 5, target: 800, name: 'Sinh viên tham dự seminar', plus: '+', time: 3 },
        { id: 6, target: 700, name: 'Số lượng tham gia tranning', plus: '+', time: 4 }
    ]);
    return (
        <div className='container'>
            <div className='mx-4 row'>
                {counters.map((counter) => (
                    <Counter
                        key={counter.id}
                        target={counter.target}
                        name={counter.name}
                        plus={counter.plus}
                        time={counter.time}
                    />
                ))}
            </div>
        </div>
    );
}