import React from 'react'
import { Container, Row } from 'react-bootstrap'

export default function Section3() {
    return (
        <Container className='d-flex mt-2 flex-column align-items-center'>
            <Row>
                <h2 className='hh'>Video giới thiệu</h2>
            </Row>
            <Row>
                <video src={require('../../assets/videos/spit.mp4')} controls
                    style={{ width: '100%', height: 'auto', maxWidth: '800px', maxHeight: '450px' }}
                ></video>
            </Row>
        </Container>
    )
}
