import React from 'react'
import { Col, Container, Row } from 'react-bootstrap'
import Timeline from '@mui/lab/Timeline';
import TimelineItem from '@mui/lab/TimelineItem';
import TimelineSeparator from '@mui/lab/TimelineSeparator';
import TimelineConnector from '@mui/lab/TimelineConnector';
import TimelineContent from '@mui/lab/TimelineContent';
import TimelineDot from '@mui/lab/TimelineDot';




export default function Section1() {
    return (
        <Container fluid>
            <Container  >
                <Timeline position="alternate">
                    <TimelineItem>
                        <TimelineSeparator>
                            <TimelineDot />
                            <TimelineConnector />
                        </TimelineSeparator>
                        <TimelineContent>
                            <Col data-aos="fade-left" data-aos-duration="1200">
                                <Row className='mb-3 d-flex  flex-md-row flex-column-reverse'>
                                    <Col xs={12} md={6} ><img alt='none' className='w-75' src={require('../../assets/img/banner2.png')} /></Col>
                                    <Col xs={12} md={6}>
                                        <h4>Seminar</h4>
                                        <p>CLB SPIT tổ chức seminar về lập trình, giúp sinh viên nắm bắt kiến thức mới nhất</p>
                                    </Col>
                                </Row>
                            </Col>
                        </TimelineContent>
                    </TimelineItem>

                    <TimelineItem>
                        <TimelineSeparator>
                            <TimelineDot />
                            <TimelineConnector />
                        </TimelineSeparator>
                        <TimelineContent><Col data-aos="fade-right" data-aos-duration="1200">
                            <Row className='mb-3 d-flex  flex-md-row flex-column-reverse'>
                                <Col xs={12} md={6}>
                                    <h4>Seminar</h4>
                                    <p>CLB SPIT tổ chức seminar về lập trình, giúp sinh viên nắm bắt kiến thức mới nhất</p>
                                </Col>
                                <Col xs={12} md={6} ><img alt='none' className='w-75' src={require('../../assets/img/banner2.png')} /></Col>
                            </Row>
                        </Col></TimelineContent>
                    </TimelineItem>
                    <TimelineItem>
                        <TimelineSeparator>
                            <TimelineDot />
                            <TimelineConnector />
                        </TimelineSeparator>
                        <TimelineContent>
                            <Col data-aos="fade-left" data-aos-duration="1200">
                                <Row className='mb-3 d-flex  flex-md-row flex-column-reverse'>
                                    <Col xs={12} md={6} ><img alt='none' className='w-75' src={require('../../assets/img/banner2.png')} /></Col>
                                    <Col xs={12} md={6}>
                                        <h4>Seminar</h4>
                                        <p>CLB SPIT tổ chức seminar về lập trình, giúp sinh viên nắm bắt kiến thức mới nhất</p>
                                    </Col>
                                </Row>
                            </Col>
                        </TimelineContent>
                    </TimelineItem>
                    <TimelineItem>
                        <TimelineSeparator>
                            <TimelineDot />
                            <TimelineConnector />
                        </TimelineSeparator>
                        <TimelineContent>
                            <Col data-aos="fade-right" data-aos-duration="1200">
                                <Row className='mb-3 d-flex  flex-md-row flex-column-reverse'>
                                    <Col xs={12} md={6}>
                                        <h4>Seminar</h4>
                                        <p>CLB SPIT tổ chức seminar về lập trình, giúp sinh viên nắm bắt kiến thức mới nhất</p>
                                    </Col>
                                    <Col xs={12} md={6} ><img alt='none' className='w-75' src={require('../../assets/img/banner2.png')} /></Col>
                                </Row>
                            </Col>
                        </TimelineContent>
                    </TimelineItem>
                </Timeline>
            </Container>
        </Container>
    )
}

