//import libraries and frameworks
import React from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';
import 'aos/dist/aos.css';
// import "@material-tailwind/react/tailwind.css";
//import styles
import './assets/css/config.css'
import './assets/font/roboto.css'
import './assets/css/Custom.css'
import './assets/css/reponsive.css'
//import pages
import App from './App';
import About from './screens/Ttv';
import Home from './screens/Home';
import Intro from './screens/Intro';
import Activitie from './screens/Activitie';
import News from './screens/News';
import Page404 from './screens/Page404';
//News 
import NewsIndex from './pages/PageNews/NewsIndex';
import News1 from './pages/PageNews/News1';
import News2 from './pages/PageNews/News2';
import News3 from './pages/PageNews/News3';
//Render
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <BrowserRouter basename={process.env.PUBLIC_URL}>
      <Routes>
        <Route path='/' element={<App />}>
          <Route index element={<Home />} />
          <Route path='intro' element={<Intro />} />
          <Route path='acti' element={<Activitie />} />
          <Route path='news' element={<News />} >
            <Route index element={<NewsIndex />} />
            <Route path='news1' element={<News1 />} />
            <Route path='news2' element={<News2 />} />
            <Route path='news3' element={<News3 />} />
            <Route path='*' element={<Page404 />} />
          </Route>
          <Route path='ttv' element={<About />} />
          <Route path='*' element={<Page404 />} />
        </Route>
      </Routes>
    </BrowserRouter>
  </React.StrictMode>
);

